  1	import * as React from 'react';
  2	import { useACMSafeFetch } from '@odf/mco/hooks';
  3	import { SearchResultItemType } from '@odf/mco/types';
  4	import {
  5	  getLabelsFromSearchResult,
  6	  queryK8sResourceFromCluster,
  7	} from '@odf/mco/utils';
  8	import { StatusBox } from '@odf/shared/generic/status-box';
  9	import { LazyLabelExpressionSelector } from '@odf/shared/label-expression-selector';
 10	import { PersistentVolumeClaimModel } from '@odf/shared/models';
 11	import { getName } from '@odf/shared/selectors';
 12	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 13	import { getValidatedProp } from '@odf/shared/utils';
 14	import {
 15	  K8sResourceCommon,
 16	  MatchExpression,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import {
 19	  FormGroup,
 20	  FormHelperText,
 21	  HelperText,
 22	  HelperTextItem,
 23	} from '@patternfly/react-core';
 24	import {
 25	  EnrollDiscoveredApplicationAction,
 26	  EnrollDiscoveredApplicationStateType,
 27	} from '../../utils/reducer';
 28	import './configuration-step.scss';
 29	
 30	const getLabelOptions = (
 31	  searchResultItem: SearchResultItemType[]
 32	): LabelOptionsType =>
 33	  searchResultItem?.reduce(
 34	    (acc, item) => {
 35	      const labels = getLabelsFromSearchResult(item);
 36	      // Separate PVC labels from other K8s resource labels
 37	      const isPVCKind = item.kind === PersistentVolumeClaimModel.kind;
 38	      Object.entries(labels)?.forEach(([key, values]) => {
 39	        if (isPVCKind) {
 40	          const valuesSet = new Set([
 41	            ...(acc['pvcLabels']?.[key] || []),
 42	            ...values,
 43	          ]);
 44	          acc['pvcLabels'][key] = Array.from(valuesSet);
 45	        } else {
 46	          const valuesSet = new Set([
 47	            ...(acc['k8sResourceLabel']?.[key] || []),
 48	            ...values,
 49	          ]);
 50	          acc['k8sResourceLabel'][key] = Array.from(valuesSet);
 51	        }
 52	      });
 53	      return acc;
 54	    },
 55	    { pvcLabels: {}, k8sResourceLabel: {} }
 56	  );
 57	
 58	export const ResourceLabelSelection: React.FC<ResourceLabelSelectionProps> = ({
 59	  k8sResourceLabelExpressions,
 60	  pvcLabelExpressions,
 61	  clusterName,
 62	  namespaces,
 63	  isValidationEnabled,
 64	  dispatch,
 65	}) => {
 66	  const { t } = useCustomTranslation();
 67	
 68	  const searchQuery = React.useMemo(
 69	    () => queryK8sResourceFromCluster(clusterName, namespaces.map(getName)),
 70	    [clusterName, namespaces]
 71	  );
 72	
 73	  // ACM search proxy API call
 74	  const [searchResult, searchError, searchLoaded] =
 75	    useACMSafeFetch(searchQuery);
 76	
 77	  const labelOptions = React.useMemo(() => {
 78	    if (searchLoaded && !searchError) {
 79	      return getLabelOptions(searchResult?.data.searchResult?.[0]?.items || []);
 80	    }
 81	    return { pvcLabels: {}, k8sResourceLabel: {} };
 82	  }, [searchResult, searchLoaded, searchError]);
 83	
 84	  const k8sResourceLabelValidated = getValidatedProp(
 85	    isValidationEnabled && !k8sResourceLabelExpressions
 86	  );
 87	
 88	  const pvcLabelValidated = getValidatedProp(
 89	    isValidationEnabled && !pvcLabelExpressions
 90	  );
 91	
 92	  const setK8sResourceLabelExpressions = (expressions: MatchExpression[]) =>
 93	    dispatch({
 94	      type: EnrollDiscoveredApplicationStateType.SET_K8S_RESOURCE_LABEL_EXPRESSIONS,
 95	      payload: expressions,
 96	    });
 97	
 98	  const setPVCLabelExpressions = (expressions: MatchExpression[]) =>
 99	    dispatch({
100	      type: EnrollDiscoveredApplicationStateType.SET_PVC_LABEL_EXPRESSIONS,
101	      payload: expressions,
102	    });
103	
104	  return searchLoaded && !searchError ? (
105	    <>
106	      <FormGroup
107	        label={t('Label expressions')}
108	        fieldId="protection-method-selection"
109	        isRequired
110	      >
111	        <FormHelperText>
112	          <HelperText>
113	            <HelperTextItem variant={k8sResourceLabelValidated}>
114	              {k8sResourceLabelValidated === 'error'
115	                ? t('Required')
116	                : t(
117	                    'Protect all your Kubernetes objects matching the selected resource label value.'
118	                  )}
119	            </HelperTextItem>
120	          </HelperText>
121	        </FormHelperText>
122	        <LazyLabelExpressionSelector
123	          selectedExpressions={k8sResourceLabelExpressions}
124	          labels={labelOptions.k8sResourceLabel}
125	          isValidationEnabled={isValidationEnabled}
126	          onChange={setK8sResourceLabelExpressions}
127	        />
128	      </FormGroup>
129	      <FormGroup
130	        label={t('PVC label selectors')}
131	        fieldId="protection-method-selection"
132	        isRequired
133	      >
134	        <FormHelperText>
135	          <HelperText>
136	            <HelperTextItem variant={pvcLabelValidated}>
137	              {pvcLabelValidated === 'error'
138	                ? t('Required')
139	                : t(
140	                    'Protect all your volumes that match the selected PVC labels'
141	                  )}
142	            </HelperTextItem>
143	          </HelperText>
144	        </FormHelperText>
145	        <LazyLabelExpressionSelector
146	          selectedExpressions={pvcLabelExpressions}
147	          labels={labelOptions.pvcLabels}
148	          isValidationEnabled={isValidationEnabled}
149	          onChange={setPVCLabelExpressions}
150	          addExpressionString={t('Add PVC label selector')}
151	        />
152	      </FormGroup>
153	    </>
154	  ) : (
155	    <StatusBox loaded={searchLoaded} loadError={searchError} />
156	  );
157	};
158	
159	type LabelOptionsType = {
160	  pvcLabels: { [key in string]: string[] };
161	  k8sResourceLabel: { [key in string]: string[] };
162	};
163	
164	type ResourceLabelSelectionProps = {
165	  // Selected k8s resource label selector expressions
166	  k8sResourceLabelExpressions: MatchExpression[];
167	  // Selected PVC label selector expressions
168	  pvcLabelExpressions: MatchExpression[];
169	  // Selected discovered application deployment cluster
170	  clusterName: string;
171	  // Selected discovered application namespaces
172	  namespaces: K8sResourceCommon[];
173	  // Form validation enabled/disabled
174	  isValidationEnabled: boolean;
175	  // Update state
176	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>;
177	};

